import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  Mic, 
  MicOff, 
  Send, 
  Pause, 
  Play, 
  Square,
  MessageCircle,
  Clock,
  User,
  Bot
} from 'lucide-react';

const MockInterview: React.FC = () => {
  const { sessionId } = useParams<{ sessionId: string }>();
  const navigate = useNavigate();
  const [isRecording, setIsRecording] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [transcript, setTranscript] = useState<Array<{
    id: string;
    speaker: 'STUDENT' | 'AI_INTERVIEWER';
    message: string;
    timestamp: string;
  }>>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [sessionTime, setSessionTime] = useState(0);

  // Mock session data
  const session = {
    id: sessionId,
    title: 'Software Engineering Mock Interview',
    duration: 45,
    questions: [
      'Tell me about yourself and your background in software engineering.',
      'Can you explain the difference between a stack and a queue?',
      'How would you design a URL shortening service?',
      'What is the time complexity of binary search?',
      'Tell me about a challenging project you worked on.',
    ]
  };

  // Mock AI responses
  const aiResponses = [
    'Thank you for that introduction. I can see you have a strong foundation in software development. Let\'s dive into some technical questions.',
    'Excellent! You clearly understand the fundamental data structures. Let\'s move on to a system design question.',
    'That\'s a good approach to the system design. I like how you considered scalability and performance.',
    'Perfect! You\'ve got the algorithmic concepts down. Let\'s talk about your experience.',
    'Thank you for sharing that experience. It shows strong problem-solving skills.',
  ];

  useEffect(() => {
    // Start the interview with AI greeting
    setTranscript([
      {
        id: '1',
        speaker: 'AI_INTERVIEWER',
        message: `Hello! I'm your AI interviewer for the ${session.title}. I'll be asking you a series of questions to assess your skills. Let's begin with the first question: ${session.questions[0]}`,
        timestamp: new Date().toISOString(),
      }
    ]);

    // Timer
    const timer = setInterval(() => {
      setSessionTime(prev => prev + 1);
    }, 1000);

    return () => clearInterval(timer);
  }, [session.title, session.questions]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleSendMessage = () => {
    if (!inputMessage.trim()) return;

    const newEntry = {
      id: Date.now().toString(),
      speaker: 'STUDENT' as const,
      message: inputMessage,
      timestamp: new Date().toISOString(),
    };

    setTranscript(prev => [...prev, newEntry]);
    setInputMessage('');

    // Simulate AI response after a delay
    setTimeout(() => {
      if (currentQuestion < session.questions.length - 1) {
        const aiEntry = {
          id: (Date.now() + 1).toString(),
          speaker: 'AI_INTERVIEWER' as const,
          message: aiResponses[currentQuestion] || 'Thank you for your response. Let\'s move to the next question.',
          timestamp: new Date().toISOString(),
        };
        setTranscript(prev => [...prev, aiEntry]);
        setCurrentQuestion(prev => prev + 1);
      } else {
        const aiEntry = {
          id: (Date.now() + 1).toString(),
          speaker: 'AI_INTERVIEWER' as const,
          message: 'Thank you for completing this interview! I\'ll provide you with detailed feedback shortly.',
          timestamp: new Date().toISOString(),
        };
        setTranscript(prev => [...prev, aiEntry]);
      }
    }, 2000);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const toggleRecording = () => {
    setIsRecording(!isRecording);
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
  };

  const endInterview = () => {
    if (window.confirm('Are you sure you want to end this interview?')) {
      navigate('/');
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="bg-white rounded-lg shadow p-6 mb-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">{session.title}</h1>
            <p className="text-gray-600">Question {currentQuestion + 1} of {session.questions.length}</p>
          </div>
          <div className="flex items-center space-x-4">
            <div className="flex items-center text-gray-600">
              <Clock className="w-5 h-5 mr-2" />
              {formatTime(sessionTime)}
            </div>
            <div className="flex items-center space-x-2">
              <button
                onClick={toggleRecording}
                className={`p-2 rounded-full ${
                  isRecording ? 'bg-red-500 text-white' : 'bg-gray-200 text-gray-600'
                }`}
              >
                {isRecording ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
              </button>
              <button
                onClick={togglePause}
                className={`p-2 rounded-full ${
                  isPaused ? 'bg-yellow-500 text-white' : 'bg-gray-200 text-gray-600'
                }`}
              >
                {isPaused ? <Play className="w-5 h-5" /> : <Pause className="w-5 h-5" />}
              </button>
              <button
                onClick={endInterview}
                className="p-2 rounded-full bg-red-500 text-white"
              >
                <Square className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Interview Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Transcript */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-lg shadow">
            <div className="p-4 border-b border-gray-200">
              <h2 className="text-lg font-semibold text-gray-900">Interview Transcript</h2>
            </div>
            <div className="p-4 h-96 overflow-y-auto">
              <div className="space-y-4">
                {transcript.map((entry) => (
                  <div
                    key={entry.id}
                    className={`flex ${entry.speaker === 'STUDENT' ? 'justify-end' : 'justify-start'}`}
                  >
                    <div
                      className={`max-w-xs lg:max-w-md px-4 py-2 rounded-lg ${
                        entry.speaker === 'STUDENT'
                          ? 'bg-primary-600 text-white'
                          : 'bg-gray-100 text-gray-900'
                      }`}
                    >
                      <div className="flex items-center mb-1">
                        {entry.speaker === 'STUDENT' ? (
                          <User className="w-4 h-4 mr-2" />
                        ) : (
                          <Bot className="w-4 h-4 mr-2" />
                        )}
                        <span className="text-xs opacity-75">
                          {entry.speaker === 'STUDENT' ? 'You' : 'AI Interviewer'}
                        </span>
                      </div>
                      <p className="text-sm">{entry.message}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Current Question */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Current Question</h3>
            <div className="bg-blue-50 p-4 rounded-lg">
              <p className="text-gray-900">
                {currentQuestion < session.questions.length 
                  ? session.questions[currentQuestion]
                  : 'Interview completed!'
                }
              </p>
            </div>

            {/* Progress */}
            <div className="mt-6">
              <div className="flex justify-between text-sm text-gray-600 mb-2">
                <span>Progress</span>
                <span>{Math.round(((currentQuestion + 1) / session.questions.length) * 100)}%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div
                  className="bg-primary-600 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${((currentQuestion + 1) / session.questions.length) * 100}%` }}
                ></div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Input Area */}
      <div className="mt-6 bg-white rounded-lg shadow p-4">
        <div className="flex items-end space-x-4">
          <div className="flex-1">
            <textarea
              value={inputMessage}
              onChange={(e) => setInputMessage(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Type your response here..."
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent resize-none"
              rows={3}
            />
          </div>
          <button
            onClick={handleSendMessage}
            disabled={!inputMessage.trim()}
            className="bg-primary-600 text-white p-3 rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Send className="w-5 h-5" />
          </button>
        </div>
        <p className="text-xs text-gray-500 mt-2">
          Press Enter to send, Shift+Enter for new line
        </p>
      </div>
    </div>
  );
};

export default MockInterview;
